const meeting = $json;

const directory = {
  "Brandon Stewart": "brandon@blazeproperty.com",
  "Amy": "amy@blazeproperty.com",
  "Breanna": "breanna@blazeproperty.com",
  "Debbie": "debbie@blazeproperty.com",
  "Dede": "dede@blazeproperty.com",
  "Shelbie": "shelbie@blazeproperty.com",
  "Chris": "chris@blazeproperty.com",
  "Ashlie": "ashlie@blazeproperty.com"
};

const required = ["brandon@blazeproperty.com"];

const participants = meeting.participants || [];

const resolved = [];

for (const p of participants) {
  if (!p) continue;
  const v = String(p).trim();

  if (v.includes('@')) {
    resolved.push(v.toLowerCase());
    continue;
  }

  if (directory[v]) {
    resolved.push(directory[v]);
  }
}

const fallback = directory[meeting.manager_name];
if (fallback) resolved.push(fallback);

const recipients = [...new Set([...required, ...resolved])];

return [{ json: { ...meeting, recipients } }];

const m = $json;

const formatList = (arr) => arr && arr.length ? arr.map(i => `• ${i}`).join('<br>') : 'None';

const changes = formatList(m.summary_structured?.changes);
const issues = formatList(m.summary_structured?.issues);
const decisions = formatList(m.summary_structured?.decisions);

const actions = (m.actions || []).map(a => `
  <div style="margin-bottom:10px;">
    <b>${a.description}</b><br>
    Owner: ${a.owner}<br>
    Due: ${a.due_date}${a.property_name ? `<br>Property: ${a.property_name}` : ''}
  </div>
`).join('');

const body = `
<div style="font-family:Arial;font-size:14px;">

<p><b>Meeting Follow-Up – ${m.manager_name}</b></p>

<h3>Summary</h3>
${changes}

<h3>Key Issues</h3>
${issues}

<h3>Decisions</h3>
${decisions}

<h3>Action Items</h3>
${actions}

<p>Please review and begin execution on assigned items immediately.</p>

<p>- Brandon</p>
</div>
`;

const dt = new Date(m.meeting_datetime);
const subject = `Meeting Follow-Up – ${m.manager_name} – ${dt.toLocaleDateString()}`;

return [{ json: { ...m, subject, body } }];

